def run() -> None:
    conn = sqlite3.connect(DB_PATH)
    conn.execute("PRAGMA foreign_keys = ON")
    try:
        updated = 0
        for content_id, lang, dice_entries in DICE_ENTRIES:
            cur = conn.execute(
                "UPDATE content_i18n SET dice_entries = ? WHERE content_id = ? AND lang = ? AND dice_entries IS NULL",
                (dice_entries, content_id, lang),
            )
            updated += cur.rowcount
        conn.commit()
        print(f"Done — {updated} content_i18n rows updated with ru/ua dice_entries.")
    finally:
        conn.close()


if __name__ == "__main__":
    run()
